#include <bits/stdc++.h>
using namespace std;

int n, m, LOG;
vector<vector<pair<int,int>>> adj;
vector<vector<int>> up;
vector<int> depthArr;
vector<long long> distArr;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    cin >> n;
    adj.assign(n + 1, {});
    for (int i = 0; i < n - 1; i++) {
        int u, v, w; cin >> u >> v >> w;
        adj[u].push_back({v, w});
        adj[v].push_back({u, w});
    }
    LOG = 1;
    while ((1 << LOG) < n) LOG++;
    LOG++;
    up.assign(LOG, vector<int>(n + 1, 0));
    depthArr.assign(n + 1, 0);
    distArr.assign(n + 1, 0);
    vector<bool> visited(n + 1, false);
    queue<int> q;
    q.push(1);
    visited[1] = true;
    up[0][1] = 0;
    depthArr[1] = 0;
    distArr[1] = 0;
    while (!q.empty()) {
        int cur = q.front(); q.pop();
        for (auto& e : adj[cur]) {
            int nxt = e.first, w = e.second;
            if (!visited[nxt]) {
                visited[nxt] = true;
                up[0][nxt] = cur;
                depthArr[nxt] = depthArr[cur] + 1;
                distArr[nxt] = distArr[cur] + w;
                q.push(nxt);
            }
        }
    }
    for (int k = 1; k < LOG; k++)
        for (int v = 1; v <= n; v++)
            up[k][v] = up[k-1][up[k-1][v]];
    cin >> m;
    while (m--) {
        int a, b; cin >> a >> b;
        int ra = a, rb = b;
        if (depthArr[ra] < depthArr[rb]) swap(ra, rb);
        int diff = depthArr[ra] - depthArr[rb];
        for (int k = 0; k < LOG; k++)
            if (diff & (1 << k)) ra = up[k][ra];
        int lca;
        if (ra == rb) {
            lca = ra;
        } else {
            for (int k = LOG - 1; k >= 0; k--) {
                if (up[k][ra] != up[k][rb]) {
                    ra = up[k][ra];
                    rb = up[k][rb];
                }
            }
            lca = up[0][ra];
        }
        long long ans = distArr[a] + distArr[b] - 2LL * distArr[lca];
        cout << ans << "\n";
    }
    return 0;
}
